import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void shortcutViaIntermediateNode() {
        // Direct 0→1 costs 4; detour 0→2→1 costs 1+2=3
        int[][] edges = {{0,1,4},{0,2,1},{2,1,2}};
        assertEquals(3, new Solution().dijkstra(3, edges, 0, 1));
    }

    @Test
    void srcEqualsDst_returnsZero() {
        int[][] edges = {{0,1,5}};
        assertEquals(0, new Solution().dijkstra(2, edges, 1, 1));
    }

    @Test
    void unreachable_returnsMinusOne() {
        // Edges go 0→1 and 0→2 only; cannot reach 3
        int[][] edges = {{0,1,1},{0,2,2}};
        assertEquals(-1, new Solution().dijkstra(4, edges, 0, 3));
    }

    @Test
    void singleEdge_directPath() {
        int[][] edges = {{0,1,7}};
        assertEquals(7, new Solution().dijkstra(2, edges, 0, 1));
    }

    @Test
    void directedOnly_noReverseEdge() {
        // Edge 0→1 exists but not 1→0
        int[][] edges = {{0,1,3}};
        assertEquals(-1, new Solution().dijkstra(2, edges, 1, 0));
    }

    @Test
    void multiplePathsPicksMinimum() {
        // Paths 0→3: (0→1→3)=1+10=11, (0→2→3)=4+2=6, (0→1→2→3)=1+3+2=6
        int[][] edges = {{0,1,1},{0,2,4},{1,2,3},{1,3,10},{2,3,2}};
        assertEquals(6, new Solution().dijkstra(4, edges, 0, 3));
    }

    @Test
    void zeroWeightEdges() {
        int[][] edges = {{0,1,0},{1,2,0},{2,3,5}};
        assertEquals(5, new Solution().dijkstra(4, edges, 0, 3));
    }
}
